class SecurePaymentProvider extends InheritedWidget {
  final String merchantId;
  final bool isProduction;
  
  const SecurePaymentProvider({
    Key? key,
    required this.merchantId,
    required this.isProduction,
    required Widget child,
  }) : super(key: key, child: child);
  
  static SecurePaymentProvider of(BuildContext context) {
    return context.dependOnInheritedWidgetOfExactType<SecurePaymentProvider>()!;
  }
  
  @override
  bool updateShouldNotify(SecurePaymentProvider oldWidget) {
    return merchantId != oldWidget.merchantId || isProduction != oldWidget.isProduction;
  }
